<div class="row g-4">
    <!-- 왼쪽: 이벤트 상세 설명 이미지 (기다란 형태) -->
    <div class="col-lg-4 col-md-5">
        <div class="card event-card p-2">
            {% if event.DetailImageUrl %}
            <img src="{{ event.DetailImageUrl }}" class="img-fluid rounded-4 w-100" alt="Event Detail" style="cursor: pointer;" onclick="openImageModal(this.src)">
            {% elif event.ImageUrl %}
            <img src="{{ event.ImageUrl }}" class="img-fluid rounded-4 w-100" alt="Event Detail" style="cursor: pointer;" onclick="openImageModal(this.src)">
            {% endif %}
        </div>
    </div>

    <!-- 오른쪽: 정보 및 재고 현황 -->
    <div class="col-lg-8 col-md-7">
        <!-- 이벤트 요약 카드 -->
        <div class="card event-card p-4 p-lg-5 mb-4">
            <div class="d-flex justify-content-between align-items-start mb-4">
                <div>
                    <h2 class="fw-800 mb-2">
                        {{ event.EventName }}
                        {% if event.GiftID %}
                        <span class="ms-1" style="cursor: help; font-size: 1.2rem;" data-bs-toggle="tooltip" data-bs-placement="top" title="Gift ID: {{ event.GiftID }}">🎁</span>
                        {% endif %}
                    </h2>
                    <p class="text-muted mb-0">일정: {{ event.ProgressStartDate | default('-', true) }} ~ {{ event.ProgressEndDate | default('-', true) }}</p>
                </div>

                {% if event.GiftID %}
                <button id="updateBtn" class="btn btn-update btn-outline-primary shadow-sm" title="즉시 갱신 요청" style="width: 44px; height: 44px; padding: 0; display: flex; align-items: center; justify-content: center;">
                    <i class="bi bi-arrow-clockwise fs-5"></i>
                    <div class="spinner-border spinner-border-sm text-primary d-none" role="status"></div>
                </button>
                {% else %}
                <button id="scanBtn" class="btn btn-update btn-outline-warning shadow-sm" title="GiftID 찾기 (스캔)" style="width: auto; height: 44px; padding: 0 1rem; display: flex; align-items: center; justify-content: center; gap: 0.5rem;">
                    <i class="bi bi-search fs-5"></i>
                    <span class="fw-bold">GiftID 찾기</span>
                    <div class="spinner-border spinner-border-sm text-warning d-none" role="status"></div>
                </button>
                {% endif %}
            </div>

            {% if not event.GiftID %}
            <div class="alert alert-dark d-flex align-items-center" role="alert">
                <i class="bi bi-exclamation-triangle-fill text-warning me-2"></i>
                <div>
                    아직 굿즈 정보(GiftID)가 매칭되지 않은 이벤트입니다. 상단의 <strong>'GiftID 찾기'</strong> 버튼을 눌러 스캔을 시도해보세요.
                </div>
            </div>
            {% endif %}

            <div class="row g-4 mb-4">
                <span class="text-muted me-3">전체 잔여 수량</span>
                <h3 class="fw-800 text-primary mb-0">{{ total_stock | format_stock }}</h3>
            </div>
        </div>

        <!-- 지점별 현황 섹션 -->
        <div class="mb-4 d-flex align-items-center">
            <h4 class="fw-700 mb-0">📍 지점별 현황</h4>
            <span class="ms-3 text-muted small">지점을 클릭하면 그래프가 표시됩니다.</span>
        </div>

        <div class="table-responsive">
            <table class="table">
                <thead class="text-muted small">
                    <tr>
                        <th class="ps-4">지역</th>
                        <th>영화관</th>
                        <th>재고 상태</th>
                        <th class="pe-4 text-end">업데이트</th>
                    </tr>
                </thead>
                <tbody>
                    {% for item in inventory %}
                    <tr class="cursor-pointer" onclick="showChart('{{ item.CinemaID }}', '{{ item.CinemaName }}')" style="cursor: pointer;">
                        <td class="ps-4 text-muted">{{ item.DivisionName }}</td>
                        <td class="fw-700">{{ item.CinemaName }}</td>
                        <td>
                            {% if item.ItemCount >= 50 %}
                            <span class="stock-badge badge-success">{{ item.ItemCount | format_stock }}</span>
                            {% elif item.ItemCount > 0 %}
                            <span class="stock-badge badge-warning">{{ item.ItemCount | format_stock }}</span>
                            {% else %}
                            <span class="stock-badge badge-danger">{{ item.ItemCount | format_stock }}</span>
                            {% endif %}
                        </td>
                        <td class="pe-4 text-end text-muted small">{{ item.LastUpdated.strftime('%m-%d %H:%M') }}</td>
                    </tr>
                    {% else %}
                    <tr>
                        <td colspan="4" class="text-center py-5 text-muted">수집된 재고 정보가 없습니다.</td>
                    </tr>
                    {% endfor %}
                </tbody>
            </table>
        </div>
    </div>
</div>

