<script>
let stockChart = null;

async function showChart(cinemaId, cinemaName) {
    const response = await fetch(`/api/history/{{ event.EventID }}/${cinemaId}`);
    const data = await response.json();

    const modal = new bootstrap.Modal(document.getElementById('chartModal'));
    document.getElementById('chartTitle').innerText = `${cinemaName} — 수량 변동 추이`;
    modal.show();

    const ctx = document.getElementById('stockChart').getContext('2d');
    if (stockChart) stockChart.destroy();

    const gradient = ctx.createLinearGradient(0, 0, 0, 400);
    gradient.addColorStop(0, 'rgba(96, 165, 250, 0.2)');
    gradient.addColorStop(1, 'rgba(96, 165, 250, 0)');

        stockChart = new Chart(ctx, {

            type: 'line',

            data: {

                datasets: [{

                    label: '잔여 수량',

                    data: data.map(d => ({ x: d.time, y: d.count, actualTime: d.actual_time })),

                    borderColor: '#60a5fa',

                    borderWidth: 3,

                    backgroundColor: gradient,

                    tension: 0.4,

                    fill: true,

                    pointBackgroundColor: '#fff',

                    pointBorderColor: '#60a5fa',

                    pointBorderWidth: 2,

                    pointRadius: 4,

                    pointHoverRadius: 6

                }]

            },

            options: {

                responsive: true,

                maintainAspectRatio: false,

                interaction: { intersect: false, mode: 'index' },

                scales: {

                    y: { 

                        beginAtZero: true, 

                        grid: { color: '#334155' },

                        ticks: { stepSize: 1, color: '#94a3b8' }

                    },

                    x: {

                        type: 'time',

                        time: {

                            tooltipFormat: 'MM-dd HH:mm',

                            displayFormats: {

                                hour: 'MM-dd HH:mm',

                                day: 'MM-dd'

                            }

                        },

                        grid: { display: false },

                        ticks: { color: '#94a3b8', autoSkip: true, maxRotation: 0 }

                    }

                },

                plugins: {

                    legend: { display: false },

                    tooltip: {

                        callbacks: {

                            label: function(context) {

                                const point = context.raw || {};

                                const count = context.parsed.y;

                                const actual = point.actualTime ? `실제 수집: ${point.actualTime}` : '';

                                return actual ? [`잔여 수량: ${count}`, actual] : `잔여 수량: ${count}`;

                            }

                        }

                    }

                }

            }

        });
}

    const updateBtn = document.getElementById('updateBtn');
    if (updateBtn) {
        updateBtn.addEventListener('click', async () => {
            const btn = updateBtn;
            const icon = btn.querySelector('i');
            const spinner = btn.querySelector('.spinner-border');

            btn.disabled = true;
            icon.classList.add('d-none');
            spinner.classList.remove('d-none');
            try {
                const response = await fetch('/api/update/{{ event.EventID }}', { method: 'POST' });
                if (response.ok) showToast('재고 갱신 요청을 보냈습니다. 잠시 후 새로고침 하세요.', 'success');
            } catch (e) {
                showToast('연결 오류가 발생했습니다.', 'danger');
            } finally {
                setTimeout(() => {
                    btn.disabled = false;
                    icon.classList.remove('d-none');
                    spinner.classList.add('d-none');
                }, 2000);
            }
        });
    }

    const scanBtn = document.getElementById('scanBtn');
    if (scanBtn) {
        scanBtn.addEventListener('click', async () => {
            const btn = scanBtn;
            const icon = btn.querySelector('i');
            const spinner = btn.querySelector('.spinner-border');

            btn.disabled = true;
            icon.classList.add('d-none');
            spinner.classList.remove('d-none');
            try {
                const response = await fetch('/api/scan-gift/{{ event.EventID }}', { method: 'POST' });
                if (response.ok) showToast('GiftID 스캔 작업을 시작했습니다. (약 1~2분 소요)', 'warning');
            } catch (e) {
                showToast('연결 오류가 발생했습니다.', 'danger');
            } finally {
                setTimeout(() => {
                    btn.disabled = false;
                    icon.classList.remove('d-none');
                    spinner.classList.add('d-none');
                }, 2000);
            }
        });
    }
</script>

